+    #[test]
+    fn try_acquire_group_all_free() {
+        let mgr = PaneWorkflowLockManager::new();
+        let result = mgr.try_acquire_group(&[1, 2, 3], "workflow_a", "exec-1");
+        assert!(result.is_acquired());
+        if let GroupLockResult::Acquired { locked_panes } = result {
